   104→    }
   105→
   106→    // Subscribe to singleton
   107→    const unsubscribe = subscriptionState.subscribe((expired) => {
   108→      setIsExpired(expired);
   109→    });
   110→    return unsubscribe;
   111→  }, []);
   112→
   113→  // Whitelist Logic
   114→  const isWhitelisted =
   115→    location.pathname.startsWith("/salon/my-plan") ||
   116→    location.pathname.startsWith("/salon/plano") ||
   117→    location.pathname.startsWith("/login") ||
   118→    location.pathname.startsWith("/register") ||
   119→    location.pathname.startsWith("/onboarding") ||
   120→    location.pathname === "/"; 
   121→
   122→  const isSalonRoute = location.pathname.startsWith("/salon/");
   123→
   124→  const handleConfirm = () => {
   125→    navigate("/salon/my-plan");
   126→  };
   127→
   128→  // Bypass logic for Super Admin (Easy Salon)
   129→  const isSuperAdmin = user?.role === "Easy Salon";
   130→
   131→  // Don't show if whitelisted or super admin
   132→  if (isWhitelisted || isSuperAdmin) {
   133→    return null;
   134→  }
   135→
   136→  return (
   137→    <SubscriptionAlertModal
   138→      isOpen={isExpired}
   139→      onConfirm={handleConfirm}
   140→    />
   141→  );
   142→}
